cat <<'EOF' > /tmp/stackalloc_test/Program.cs
Span<nint> nints = stackalloc nint[4];
for (int i = 0; i < nints.Length; i++)
    nints[i] = i * 10;

Span<nuint> nuints = stackalloc nuint[4];
for (int i = 0; i < nuints.Length; i++)
    nuints[i] = (nuint)(i * 20);

Console.WriteLine("nint span:");
foreach (var v in nints) Console.WriteLine($"  {v}");
Console.WriteLine("nuint span:");
foreach (var v in nuints) Console.WriteLine($"  {v}");
EOF
